import React from 'react';
import { graphql } from 'gatsby';
import { NoticeType } from 'types/data';
import NoticeWrapper from '@components/NoticeWrapper';
import NoticeList from '@components/NoticeList';

interface IProps {
  data: {
    allContentfulNotices: {
      nodes: NoticeType[];
    };
  };
}

const notice = ({ data }: IProps) => {
  return (
    <NoticeWrapper>
      <NoticeList data={data.allContentfulNotices.nodes} />
    </NoticeWrapper>
  );
};

export default notice;

export const data = graphql`
  query {
    allContentfulNotices {
      nodes {
        id
        title
        createdAt
        content {
          content
        }
        tag
      }
    }
  }
`;
