import { NoticeType } from 'types/data';
import React from 'react';
import moment from 'moment';

interface IProps {
  data: NoticeType[];
}

const NoticeList = ({ data }: IProps) => {
  return (
    <div>
      {data.map((m) => (
        <>
          <h2>{m.title}</h2>
          <h4>{m.content.content}</h4>
          <p>{moment(m.createdAt).format('YYYY-MM-DD')}</p>
        </>
      ))}
    </div>
  );
};

export default NoticeList;
