import Layout from '@components/Layout';
import React from 'react';
import { Link, graphql } from 'gatsby';
import { NoticeType } from 'types/data';
import { Tag, TagWrapper, Title } from './styles';

interface IProps {
  children: React.ReactNode;
}

const T: string[] = ['Notice', 'Academy', 'Recruit'];

const NoticeWrapper = ({ children }: IProps) => {
  return (
    <Layout>
      <Title to="/notice">공지사항</Title>
      <TagWrapper>
        {T.map((t) => (
          <Tag to={`/notice/${t.toLowerCase()}`} activeStyle={{ fontWeight: 700 }} key={t}>
            {t}
          </Tag>
        ))}
      </TagWrapper>
      {children}
    </Layout>
  );
};

export default NoticeWrapper;
